from statsmodels.nonparametric.smoothers_lowess import lowess

result = lowess(home_away_match["GD"], home_away_match["pastgame_GD"], frac=0.2)
fitted = pd.DataFrame(result, columns=["pastgame_GD", "Fitted"])
